const body = item.json.body;
const value = body.entry[0].changes[0].value;
const message = value.messages[0];
const contact = value.contacts ? value.contacts[0] : null;

// Phone normalization: strip all non-digits, keep only numbers, and prepend '+' for Supabase.
const clientPhoneRaw = message.from;
const clientPhoneNormalized = '+' + clientPhoneRaw.replace(/\D/g, '');
const businessPhone = value.metadata.display_phone_number;
const phoneId = value.metadata.phone_number_id;

let messageType = message.type || 'text';
let messageText = '';
let isButtonClick = false;
let buttonReplyId = '';
let imageUrl = '';

if (messageType === 'text') {
  messageText = message.text ? message.text.body : '';
} else if (messageType === 'interactive') {
  isButtonClick = true;
  buttonReplyId = message.interactive?.button_reply?.id || '';
  messageText = message.interactive?.button_reply?.title || '';
} else if (messageType === 'image') {
  imageUrl = message.image?.link || message.image?.url || '';
  messageText = '[Image]';
}

return {
  clientPhoneRaw,
  clientPhoneNormalized,
  clientName: contact ? contact.profile.name : "Client WhatsApp",
  messageType,
  messageText,
  isButtonClick,
  buttonReplyId,
  imageUrl,
  messageId: message.id,
  timestamp: message.timestamp,
  businessPhone,
  phoneId
};

