const messageText = $('Parse WhatsApp Message').item.json.messageText.toLowerCase();

// Language Detection
let language = 'French';
const arabicPattern = /[\u0600-\u06FF]/;
if (arabicPattern.test(messageText)) {
  language = 'Arabic';
} else if (['hello', 'hi', 'price', 'car', 'rent', 'book', 'available'].some(w => messageText.includes(w))) {
  language = 'English';
} else if (['bonjour', 'merci', 'prix', 'voiture', 'louer', 'disponible', 'tarif'].some(w => messageText.includes(w))) {
  language = 'French';
}

// Lead Score Detection
let leadScore = null;
const hotKeywords = ['book', 'reserve', 'rent', 'louer', 'réservation', 'disponible', 'available', 'حجز', 'استئجار'];
const warmKeywords = ['prix', 'cost', 'how much', 'combien', 'tarif', 'ثمن', 'سعر'];

if (hotKeywords.some(w => messageText.includes(w))) {
  leadScore = 'hot';
} else if (warmKeywords.some(w => messageText.includes(w))) {
  leadScore = 'warm';
} else {
  leadScore = 'cold';
}

return { language, leadScore };

