  text += `${index + 1}. ${brand} ${model} ${year ? '(' + year + ')' : ''} - ${price} DZD/day [${transmission}, ${fuel}]\n`;
});

return { fleetText: text };

const fleet = $('Route2: Fetch Cars').item ? [ $('Route2: Fetch Cars').item.json ] : items.map(i => i.json);
const bookings = items.map(i => i.json);

let text = "AVAILABLE CARS FOR IMMEDIATE BOOKING:\n";
fleet.forEach((car, index) => {
  const isBooked = bookings.some(b => b.car_id === car.id);
  if (!isBooked) {
    text += `${index + 1}. ${car.brand} ${car.model} (${car.year}) - ${car.daily_rate} DZD/day\n`;
  }
});

return { fleetText: text + "\nInstructions: Propose booking available dates and ask the user to confirm dates to pre-register a pending booking." };

