  text += `${index + 1}. ${brand} ${model} ${year ? '(' + year + ')' : ''} - ${price} DZD/day [${transmission}, ${fuel}]\n`;
});

return { fleetText: text };

const messages = [...items].reverse();
if (messages.length === 0) {
  return { historyText: "No previous messages in this conversation." };
}

let text = "";
messages.forEach(msg => {
  const sender = msg.json.sender_type === 'client' ? 'Client' : 'Assistant';
  const content = msg.json.content || "";
  text += `${sender}: ${content}\n`;
});

return { historyText: text };

