const response = item.json;
let reply = "";
try {
  reply = response.body.candidates[0].content.parts[0].text;
} catch (e) {
  reply = "Désolé, nous rencontrons un petit incident technique. Veuillez nous excuser et réessayer dans un instant, ou contactez un conseiller.";
}
return {
  replyText: reply.trim()
};

